import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";
import { LiveObject } from "@liveblocks/client";

// Define the shape of Presence for each user
type Presence = {
  typing: "name" | "email" | "bio" | null;
  info: {
    name: string;
  };
};

// Define the shape of Storage
type Storage = {
  form: LiveObject<{
    name: string;
    email: string;
    bio: string;
  }>;
};

// Create the Liveblocks client
const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

// Create typed room context
export const {
  RoomProvider,
  useMyPresence,
  useUpdateMyPresence,
  useOthers,
  useStorage,
  useMutation,
} = createRoomContext<Presence, Storage>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  // Get the display name from the request body (sent by the client)
  let displayName = "Anonymous";
  try {
    const body = await request.json();
    if (body?.displayName) {
      displayName = body.displayName;
    }
  } catch {
    // ignore parse errors
  }

  // Create a session for the user
  const session = liveblocks.prepareSession(`user-${Math.random().toString(36).slice(2)}`, {
    userInfo: {
      name: displayName,
    },
  });

  // Derive room id from environment variable
  const runId = process.env.ZEALT_RUN_ID;
  const roomId = runId ? `harbor-typing-form-${runId}` : "harbor-typing-form-local";

  // Grant full access to the room
  session.allow(roomId, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new NextResponse(body, { status });
}

"use client";

import React, { useEffect, useState } from "react";
import { LiveObject } from "@liveblocks/client";
import { RoomProvider } from "../../liveblocks.config";

const ROOM_ID = process.env.NEXT_PUBLIC_ROOM_ID || "harbor-typing-form-local";

export function Room({ children }: { children: React.ReactNode }) {
  const [displayName, setDisplayName] = useState("Anonymous");

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const nameParam = params.get("name");
    if (nameParam) {
      setDisplayName(nameParam);
    }
  }, []);

  return (
    <RoomProvider
      id={ROOM_ID}
      initialPresence={{
        typing: null,
        info: { name: displayName },
      }}
      initialStorage={{
        form: new LiveObject({ name: "", email: "", bio: "" }),
      }}
    >
      {children}
    </RoomProvider>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import {
  useStorage,
  useMutation,
  useOthers,
  useUpdateMyPresence,
  useMyPresence,
} from "../../liveblocks.config";

type FieldId = "name" | "email" | "bio";

const FIELD_LABELS: Record<FieldId, string> = {
  name: "Name",
  email: "Email",
  bio: "Bio",
};

function TypingIndicator({ field }: { field: FieldId }) {
  const others = useOthers();
  const typingUsers = others.filter(
    (other) => other.presence?.typing === field
  );

  if (typingUsers.length === 0) return null;

  const label = FIELD_LABELS[field];

  return (
    <div
      data-testid={`typing-indicator-${field}`}
      style={{ fontSize: 12, color: "#888", minHeight: 18, marginBottom: 2 }}
    >
      {typingUsers.map((user, i) => {
        const userName = user.presence?.info?.name ?? "Someone";
        return (
          <span key={user.connectionId}>
            {i > 0 ? ", " : ""}
            {userName} is typing in {label}…
          </span>
        );
      })}
    </div>
  );
}

function LockOverlay({ field }: { field: FieldId }) {
  const others = useOthers();
  const isLockedByOther = others.some(
    (other) => other.presence?.typing === field
  );

  if (!isLockedByOther) return null;

  return (
    <div
      data-testid={`lock-overlay-${field}`}
      style={{
        position: "absolute",
        inset: 0,
        backgroundColor: "rgba(200, 200, 200, 0.4)",
        borderRadius: 4,
        pointerEvents: "none",
        zIndex: 1,
      }}
    />
  );
}

export function MultiplayerForm() {
  const [displayName, setDisplayName] = useState("Anonymous");
  const updateMyPresence = useUpdateMyPresence();

  // Read display name from URL query param on mount
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const nameParam = params.get("name");
    const name = nameParam || "Anonymous";
    setDisplayName(name);
    // Update presence with the resolved display name
    updateMyPresence({ info: { name } });
  }, [updateMyPresence]);

  // Read form values from Storage
  const formData = useStorage((root) => root.form);

  // Mutation to update a single field in storage
  const updateField = useMutation(
    ({ storage }, field: FieldId, value: string) => {
      storage.get("form").set(field, value);
    },
    []
  );

  const handleFocus = (field: FieldId) => {
    updateMyPresence({ typing: field });
  };

  const handleBlur = () => {
    updateMyPresence({ typing: null });
  };

  const handleChange = (field: FieldId, value: string) => {
    updateField(field, value);
    updateMyPresence({ typing: field });
  };

  if (formData === null) {
    return <div>Loading…</div>;
  }

  return (
    <main>
      <h1>Multiplayer Form</h1>
      <p>Collaborate with other users in real time.</p>

      {/* Name field */}
      <div style={{ marginTop: 24 }}>
        <label htmlFor="name">Name</label>
        <TypingIndicator field="name" />
        <div style={{ position: "relative" }}>
          <LockOverlay field="name" />
          <input
            id="name"
            data-testid="input-name"
            type="text"
            value={formData.name ?? ""}
            onFocus={() => handleFocus("name")}
            onBlur={handleBlur}
            onChange={(e) => handleChange("name", e.target.value)}
            style={{ display: "block", width: "100%", padding: 8, boxSizing: "border-box" }}
          />
        </div>
      </div>

      {/* Email field */}
      <div style={{ marginTop: 16 }}>
        <label htmlFor="email">Email</label>
        <TypingIndicator field="email" />
        <div style={{ position: "relative" }}>
          <LockOverlay field="email" />
          <input
            id="email"
            data-testid="input-email"
            type="email"
            value={formData.email ?? ""}
            onFocus={() => handleFocus("email")}
            onBlur={handleBlur}
            onChange={(e) => handleChange("email", e.target.value)}
            style={{ display: "block", width: "100%", padding: 8, boxSizing: "border-box" }}
          />
        </div>
      </div>

      {/* Bio field */}
      <div style={{ marginTop: 16 }}>
        <label htmlFor="bio">Bio</label>
        <TypingIndicator field="bio" />
        <div style={{ position: "relative" }}>
          <LockOverlay field="bio" />
          <textarea
            id="bio"
            data-testid="input-bio"
            value={formData.bio ?? ""}
            onFocus={() => handleFocus("bio")}
            onBlur={handleBlur}
            onChange={(e) => handleChange("bio", e.target.value)}
            rows={4}
            style={{ display: "block", width: "100%", padding: 8, boxSizing: "border-box" }}
          />
        </div>
      </div>
    </main>
  );
}

import React from "react";
import { Room } from "./components/Room";
import { MultiplayerForm } from "./components/MultiplayerForm";

export default function Page() {
  return (
    <Room>
      <MultiplayerForm />
    </Room>
  );
}

/** @type {import('next').NextConfig} */
const runId = process.env.ZEALT_RUN_ID;
const roomId = runId ? `harbor-typing-form-${runId}` : "harbor-typing-form-local";

const nextConfig = {
  reactStrictMode: false,
  env: {
    NEXT_PUBLIC_ROOM_ID: roomId,
  },
};
module.exports = nextConfig;

